SELECT count(*) FROM movie_keyword, title, kind_type, keyword, cast_info, name, aka_name, movie_info WHERE movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_info.movie_id = title.id;